const cp = require('child_process');
const fs = require('fs');
const os = require('os');
const projRoot = '__PROJECT_ROOT__';
const queueFile = projRoot + '/tasks/queue.md';

try {
  if (!fs.existsSync(queueFile)) {
    return [{json: {status: 'empty', message: 'No queue file'}}];
  }
  const content = fs.readFileSync(queueFile, 'utf8');
  const lines = content.split(String.fromCharCode(10));
  const idx = lines.findIndex(l => /^- \[ \]/.test(l));
  if (idx === -1) {
    return [{json: {status: 'empty', message: 'No pending tasks'}}];
  }
  const task = lines[idx].replace(/^- \[ \]\s*/, '').trim();
  if (!task) return [{json: {status: 'empty', message: 'Empty task'}}];

  // Mark in-progress
  lines[idx] = lines[idx].replace('- [ ]', '- [~]');
  fs.writeFileSync(queueFile, lines.join('
'));

  // Safe execution via temp file
  const tmp = os.tmpdir() + '/task-' + Date.now() + '.txt';
  fs.writeFileSync(tmp, task);
  let result;
  try {
    result = cp.execSync('claude -p < "' + tmp.replace(/\/g, '/') + '"', {cwd: projRoot, timeout: 300000, encoding: 'utf8', shell: true}).trim();
  } finally {
    try { fs.unlinkSync(tmp); } catch {}
  }

  // Mark done
  const updated = fs.readFileSync(queueFile, 'utf8').split(String.fromCharCode(10));
  const doneIdx = updated.findIndex(l => l.includes('[~]') && l.includes(task.substring(0, 30)));
  if (doneIdx >= 0) updated[doneIdx] = updated[doneIdx].replace('- [~]', '- [x]');
  fs.writeFileSync(queueFile, updated.join('
'));

  return [{json: {status: 'complete', task, result: result.substring(0, 2000), timestamp: new Date().toISOString()}}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
